#!/usr/bin/env python3# -*- coding: utf-8 -*-"""AU_美联储联邦基金目标利率.py因子: AU_FED_RATE = 美联储联邦基金目标利率（%）公式: 数据采集（无独立计算公式）当前状态: [OK] 正常- 数据源: AKShare macro_bank_usa_interest_rate()，L1权威- 采集逻辑: 取'数值'列最新一行- obs_date: 决议日期- bounds: [0.0, 10.0]%（历史区间）订阅优先级: 无需付费替代付费源: 无"""import sys, os as _ossys.path.insert(0, _os.path.join(_os.path.dirname(_os.path.abspath(__file__)), ".."))from common.db_utils import ensure_table, save_to_db, get_pit_dates, get_latest_valueimport akshare as akimport pandas as pdFACTOR_CODE = "AU_FED_RATE"SYMBOL = "AU"BOUNDS = (0.0, 10.0)def fetch():    """L1: AKShare 美联储联邦基金目标利率"""    print("[L1] AKShare macro_bank_usa_interest_rate()...")    df = ak.macro_bank_usa_interest_rate()    if df is None or df.empty:        raise ValueError("no data")    col_date = df.columns[1]    col_val = df.columns[2]    df = df.dropna(subset=[col_val, col_date])    df = df.sort_values(col_date)    latest = df.iloc[-1]    raw_value = float(latest[col_val])    obs_date = pd.to_datetime(latest[col_date]).date()    return raw_value, obs_dateif __name__ == "__main__":    pub_date, obs_date = get_pit_dates()    if pub_date is None:        print("-- 非交易日，跳过"); sys.exit(0)    ensure_table()    print(f"=== {FACTOR_CODE} === pub={pub_date} obs={obs_date}")    try:        raw_value, obs_date = fetch()    except Exception as e:        print(f"[L1] 失败: {e}")        val = get_latest_value(FACTOR_CODE, SYMBOL)        if val is not None:            print(f"[L4] 兜底: {val}")            save_to_db(FACTOR_CODE, SYMBOL, pub_date, obs_date, val,                       source="db_回补", source_confidence=0.5)        else:            print(f"[WARN] {FACTOR_CODE} 所有数据源均失败")        sys.exit(0)    if not (BOUNDS[0] <= raw_value <= BOUNDS[1]):        print(f"[WARN] {FACTOR_CODE}={raw_value} 超出bounds{BOUNDS}，跳过")        sys.exit(0)    save_to_db(FACTOR_CODE, SYMBOL, pub_date, obs_date, raw_value,               source="akshare", source_confidence=1.0)    print(f"[OK] {FACTOR_CODE}={raw_value}% obs={obs_date}")